create table label_example
(
    id                  char(20)      not null comment 'ID'
        primary key,
    label_id            char(20)      not null comment '标注id',
    example_status      int default 0 not null comment '标注实例状态  0待完成，1已完成',
    example_content     text          not null comment '标注内容',
    example_imgs        char(200)     null comment '实例图片组    限制5张图片',
    label_personal_id   char(20)      not null comment '标注人id             ',
    deal_with_person_id char(20)      null comment '处理人               ',
    deal_with_content   text          null comment '处理结果              ',
    deal_with_imgs      char(200)     null comment '处理图片      限制5张图片',
    deal_with_time      datetime      null comment '处理时间              ',
    is_delete           int           not null comment '逻辑删除 0存在，1删除',
    create_time         datetime      not null comment '创建时间',
    create_user         char(20)      not null comment '创建人',
    update_time         datetime      not null comment '修改时间',
    update_user         char(20)      not null comment '修改人',
    label_geojson       text          not null
)
    comment '标注实例';

